// 🎯 DETECCIÓN FIN DE CONVERSACIÓN
const lastMessage = $input.item.json.mensaje?.toLowerCase() || '';
const aiResponse = $input.item.json.output?.toLowerCase() || '';

// Frases que indican fin de conversación
const finPhrases = [
  'gracias', 'hasta luego', 'adios', 'adiós', 
  'hablamos', 'un saludo', 'nos vemos',
  'perfecto gracias', 'ok gracias', 'vale gracias',
  'muchas gracias', 'entendido gracias'
];

// Detectar si es mensaje de despedida
const isFin = finPhrases.some(phrase => 
  lastMessage.includes(phrase) || aiResponse.includes(phrase)
);

// EXTRAER DATOS DEL MENSAJE Y RESPUESTA
const texto = (lastMessage + ' ' + aiResponse).toLowerCase();

// Extraer email
const emailRegex = /[\w.-]+@[\w.-]+\.\w+/;
const email = texto.match(emailRegex)?.[0] || $input.item.json.email || '';

// Extraer teléfono (España)
const phoneRegex = /(?:\+34|0034|34)?[\s.-]?[6-9]\d{2}[\s.-]?\d{3}[\s.-]?\d{3}/;
const telefono = texto.match(phoneRegex)?.[0] || $input.item.json.telefono || '';

// Verificar que tenemos datos mínimos
const hasEmail = email && email.length > 0;
const hasTelefono = telefono && telefono.length > 0;

return {
  finConversacion: isFin && hasEmail && hasTelefono,
  hasEmail: hasEmail,
  hasTelefono: hasTelefono,
  email: email,
  telefono: telefono,
  ...($input.item.json)
};

// 📊 GENERAR RESUMEN COMPLETO
const nombre = $input.item.json.nombre || 'No proporcionado';
const email = $input.item.json.email || 'No proporcionado';
const telefono = $input.item.json.telefono || 'No proporcionado';
const tipoUsuario = $input.item.json.session_id?.split('_')[0] || 'No especificado';
const ciudad = $input.item.json.ciudad || 'No especificada';

// Obtener conversación completa
const conversacionCompleta = $input.item.json.conversacion || [];
const textoCompleto = conversacionCompleta
  .map(m => m.content || '')
  .join(' ')
  .toLowerCase();

// 🎯 DETECTAR RETO PRINCIPAL
let reto = 'No especificado';
if (textoCompleto.includes('captar') || textoCompleto.includes('clientes')) {
  reto = '🎯 Captar más clientes';
}
if (textoCompleto.includes('reputación') || textoCompleto.includes('reseñas')) {
  reto = '⭐ Mejorar reputación online';
}
if (textoCompleto.includes('automatizar')) {
  reto = '🤖 Automatizar procesos';
}
if (textoCompleto.includes('citas') || textoCompleto.includes('agenda')) {
  reto = '📅 Gestionar citas y reservas';
}
if (textoCompleto.includes('whatsapp') || textoCompleto.includes('atención')) {
  reto = '💬 Atención al cliente 24/7';
}

// 🔥 DETERMINAR NIVEL DE INTERÉS
let nivelInteres = 'MEDIO';
let emoji = '🟡';
if (email && telefono) {
  nivelInteres = 'ALTO';
  emoji = '🔴';
}

// 💬 GENERAR RESUMEN EMAIL (formato extenso)
const resumenEmail = `
RESUMEN CONVERSACIÓN - ${nombre}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

📋 DATOS CONTACTO:
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
- Nombre: ${nombre}
- Email: ${email}
- Teléfono: ${telefono}
- Tipo: ${tipoUsuario}

🏢 INFORMACIÓN DEL NEGOCIO:
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
- Ubicación: ${ciudad}

🎯 RETO PRINCIPAL:
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
${reto}

🔥 NIVEL DE INTERÉS:
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
${emoji} ${nivelInteres} ${email && telefono ? '- Proporcionó datos completos' : ''}

💬 CONVERSACIÓN COMPLETA:
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
${conversacionCompleta.map((m, i) => 
  `${i+1}. ${m.role === 'user' ? '👤 USUARIO' : '🤖 SOFÍA'}: ${m.content}`
).join('\n\n')}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
Generado: ${new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' })}
Session ID: ${$input.item.json.session_id}
`;

// 📱 GENERAR RESUMEN WHATSAPP (formato compacto)
const resumenWhatsApp = `
🤖 *NUEVO LEAD ESCAPARATE.COM*
━━━━━━━━━━━━━━━━━━━━━━━━━━━

👤 *${nombre}*
${emoji} Nivel: *${nivelInteres}*

📋 *DATOS:*
- 📧 ${email}
- 📱 ${telefono}
- 📍 ${ciudad}

🎯 *RETO:* ${reto}

🔗 Session: ${$input.item.json.session_id.substring(0, 8)}...
`;

// 📧 GENERAR ASUNTO EMAIL
const asunto = `[LEAD ${nivelInteres}] ${nombre} - ${tipoUsuario} en ${ciudad}`;

return {
  resumenEmail: resumenEmail,
  resumenWhatsApp: resumenWhatsApp,
  asunto: asunto,
  nombre: nombre,
  email: email,
  telefono: telefono,
  reto: reto,
  nivelInteres: nivelInteres,
  ...($input.item.json)
};
